// Notification templates shared by BDI Corporate and any site generated by the
// BDI website builder. Form types are: contact, newsletter, order, booking.
// Each type ships a customer-facing template (confirmation) and an admin-facing
// template (alert with action items). Brand tokens make them reusable per org.
//
// Keep this file in sync with the copy used by the website-builder generator —
// when generated sites are scaffolded, this module is copied verbatim into them
// (with tenant-specific brand tokens injected at build time).

export interface Brand {
  name: string;
  siteUrl: string;
  supportEmail: string;
  phone?: string;
  primaryColor?: string;
  accentColor?: string;
  logoUrl?: string;
}

const DEFAULT_BRAND: Brand = {
  name: "BDI Corporate",
  siteUrl: "https://bdicorporate.com",
  supportEmail: "info@bdicorporate.com",
  phone: "+961 1 000 000",
  primaryColor: "#0f172a",
  accentColor: "#0ea5e9",
};

function withDefaults(brand?: Partial<Brand>): Brand {
  return { ...DEFAULT_BRAND, ...(brand ?? {}) };
}

function escape(value: unknown): string {
  if (value == null) return "";
  return String(value).replace(/[&<>"']/g, (c) =>
    ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c] as string),
  );
}

function shell(brand: Brand, headline: string, subhead: string, body: string): string {
  return `
    <div style="font-family: system-ui, -apple-system, sans-serif; max-width: 600px; margin: 0 auto; background:#fff;">
      <div style="background: linear-gradient(135deg, ${brand.primaryColor}, ${brand.accentColor}); padding: 28px; text-align: center;">
        ${brand.logoUrl ? `<img src="${escape(brand.logoUrl)}" alt="${escape(brand.name)}" style="max-height:40px;margin-bottom:12px;"/>` : ""}
        <h1 style="color: white; margin: 0; font-size: 26px;">${escape(headline)}</h1>
        <p style="color: rgba(255,255,255,0.9); margin: 8px 0 0 0; font-size: 15px;">${escape(subhead)}</p>
      </div>
      <div style="padding: 24px;">${body}</div>
      <div style="text-align:center;padding:16px 24px;color:#94a3b8;font-size:12px;border-top:1px solid #f1f5f9;">
        ${escape(brand.name)} &middot; <a href="${escape(brand.siteUrl)}" style="color:#94a3b8;">${escape(brand.siteUrl.replace(/^https?:\/\//, ""))}</a>
      </div>
    </div>
  `;
}

function row(label: string, value: unknown): string {
  if (value == null || value === "") return "";
  return `
    <tr style="border-bottom: 1px solid #e2e8f0;">
      <td style="padding: 8px 0; color: #64748b; font-size: 14px; width: 160px;">${escape(label)}</td>
      <td style="padding: 8px 0; color: #1e293b; font-weight: 600;">${escape(value)}</td>
    </tr>
  `;
}

// ─── Contact ──────────────────────────────────────────────────────────────

export interface ContactFormPayload {
  name?: string;
  email?: string;
  phone?: string;
  city?: string;
  subject?: string;
  reason?: string;
  budget?: string;
  contact_pref?: string;
  message?: string;
}

export function renderContactCustomerEmail(form: ContactFormPayload, brandIn?: Partial<Brand>): string {
  const brand = withDefaults(brandIn);
  const body = `
    <div style="background:#f0fdf4;padding:16px;border-radius:8px;margin:0 0 16px;border-left:4px solid #059669;">
      <h4 style="margin:0 0 8px;color:#059669;">✓ Your message has been sent</h4>
      <p style="margin:0;color:#059669;font-size:14px;">Thank you for reaching out to ${escape(brand.name)}. Our team will respond within 24 hours.</p>
    </div>
    <h3 style="margin:24px 0 8px;color:#1e293b;">Your submission</h3>
    <div style="background:#f8fafc;padding:16px;border-radius:8px;margin:0 0 16px;">
      <table style="width:100%;border-collapse:collapse;">
        ${row("Name", form.name)}
        ${row("Email", form.email)}
        ${row("Phone", form.phone)}
        ${row("City", form.city)}
        ${row("Subject", form.subject)}
        ${row("Looking for", form.reason)}
        ${row("Budget", form.budget)}
        ${row("Contact preference", form.contact_pref)}
      </table>
      ${form.message ? `<div style="margin-top:16px;padding-top:16px;border-top:1px solid #e2e8f0;">
        <p style="margin:0 0 8px;color:#64748b;font-size:14px;">Your message:</p>
        <p style="margin:0;color:#1e293b;line-height:1.6;white-space:pre-wrap;">${escape(form.message)}</p>
      </div>` : ""}
    </div>
    <div style="background:#eff6ff;padding:16px;border-radius:8px;margin:0 0 16px;">
      <p style="margin:0;color:#0369a1;font-size:14px;">Need immediate help? Reach us at
        <a href="mailto:${escape(brand.supportEmail)}" style="color:#0369a1;">${escape(brand.supportEmail)}</a>${brand.phone ? ` or <a href="tel:${escape(brand.phone)}" style="color:#0369a1;">${escape(brand.phone)}</a>` : ""}.
      </p>
    </div>
  `;
  return shell(brand, "Message received", "We'll get back to you soon", body);
}

export function renderContactAdminEmail(form: ContactFormPayload, brandIn?: Partial<Brand>): string {
  const brand = withDefaults(brandIn);
  const body = `
    <div style="background:#fff7ed;padding:16px;border-radius:8px;margin:0 0 16px;border-left:4px solid #ea580c;">
      <h4 style="margin:0 0 4px;color:#ea580c;">⚡ Action required</h4>
      <p style="margin:0;color:#ea580c;font-size:14px;">Respond within 24 hours${form.contact_pref ? ` via ${escape(form.contact_pref)}` : ""}.</p>
    </div>
    <h3 style="margin:24px 0 8px;color:#1e293b;">Contact details</h3>
    <div style="background:#f8fafc;padding:16px;border-radius:8px;">
      <table style="width:100%;border-collapse:collapse;">
        ${row("Name", form.name)}
        ${form.email ? `<tr style="border-bottom:1px solid #e2e8f0;"><td style="padding:8px 0;color:#64748b;font-size:14px;width:160px;">Email</td><td style="padding:8px 0;"><a href="mailto:${escape(form.email)}" style="color:#0369a1;">${escape(form.email)}</a></td></tr>` : ""}
        ${form.phone ? `<tr style="border-bottom:1px solid #e2e8f0;"><td style="padding:8px 0;color:#64748b;font-size:14px;">Phone</td><td style="padding:8px 0;"><a href="tel:${escape(form.phone)}" style="color:#0369a1;">${escape(form.phone)}</a></td></tr>` : ""}
        ${row("City", form.city)}
        ${row("Subject", form.subject)}
        ${row("Looking for", form.reason)}
        ${row("Budget", form.budget)}
        ${row("Contact preference", form.contact_pref)}
      </table>
    </div>
    ${form.message ? `<div style="background:#eff6ff;padding:16px;border-radius:8px;margin:16px 0;">
      <h3 style="margin:0 0 12px;color:#0369a1;">Message</h3>
      <p style="margin:0;color:#1e293b;line-height:1.6;white-space:pre-wrap;">${escape(form.message)}</p>
    </div>` : ""}
  `;
  return shell(brand, "📩 New contact form", `Submission for ${brand.name}`, body);
}

