// ─── Order ──────────────────────────────────────────────────────────────

export interface OrderItem { name?: string; quantity?: number; price?: number; sku?: string; }
export interface OrderPayload {
  number?: string;
  status?: string;
  method?: string;            // stripe | whish | cash | …
  email?: string;
  phone?: string;
  name?: string;
  address1?: string;
  address2?: string;
  city?: string;
  postal?: string;
  country?: string;
  items?: OrderItem[];
  subtotal?: number;
  total?: number;
  currency?: string;
  deliveryFee?: number;
  deliveryMethod?: string;    // pickup | delivery
}

function money(amount: number | undefined, currency: string | undefined): string {
  const n = typeof amount === "number" ? amount : 0;
  const cur = (currency || "USD").toUpperCase();
  try { return new Intl.NumberFormat("en-US", { style: "currency", currency: cur }).format(n); }
  catch { return `${n.toFixed(2)} ${cur}`; }
}

function itemsTable(items: OrderItem[] | undefined, currency: string | undefined): string {
  const rows = (items || []).map((it) => `
    <tr style="border-bottom:1px solid #e2e8f0;">
      <td style="padding:10px 0;color:#1e293b;">${escape(it.name || it.sku || "Item")}</td>
      <td style="padding:10px 0;color:#64748b;text-align:center;">×${escape(it.quantity ?? 1)}</td>
      <td style="padding:10px 0;color:#1e293b;text-align:right;font-weight:600;">${escape(money((it.price ?? 0) * (it.quantity ?? 1), currency))}</td>
    </tr>
  `).join("");
  return `<table style="width:100%;border-collapse:collapse;">${rows}</table>`;
}

export function renderOrderCustomerEmail(order: OrderPayload, brandIn?: Partial<Brand>): string {
  const brand = withDefaults(brandIn);
  const body = `
    <div style="background:#f0fdf4;padding:16px;border-radius:8px;margin:0 0 16px;border-left:4px solid #059669;">
      <h4 style="margin:0 0 8px;color:#059669;">✓ Order ${order.number ? `#${escape(order.number)} ` : ""}received</h4>
      <p style="margin:0;color:#059669;font-size:14px;">${order.method === "stripe" ? "Payment confirmed." : order.method === "whish" ? "We'll confirm your Whish payment shortly." : "We'll be in touch to confirm payment and delivery."}</p>
    </div>
    <h3 style="margin:24px 0 8px;color:#1e293b;">Order summary</h3>
    <div style="background:#f8fafc;padding:16px;border-radius:8px;">
      ${itemsTable(order.items, order.currency)}
      <div style="margin-top:16px;padding-top:16px;border-top:2px solid #e2e8f0;">
        <table style="width:100%;border-collapse:collapse;">
          <tr><td style="padding:4px 0;color:#64748b;">Subtotal</td><td style="padding:4px 0;text-align:right;color:#1e293b;">${escape(money(order.subtotal, order.currency))}</td></tr>
          ${order.deliveryFee ? `<tr><td style="padding:4px 0;color:#64748b;">Delivery</td><td style="padding:4px 0;text-align:right;color:#1e293b;">${escape(money(order.deliveryFee, order.currency))}</td></tr>` : ""}
          <tr><td style="padding:8px 0 0;color:#1e293b;font-weight:700;font-size:16px;">Total</td><td style="padding:8px 0 0;text-align:right;color:#1e293b;font-weight:700;font-size:16px;">${escape(money(order.total, order.currency))}</td></tr>
        </table>
      </div>
    </div>
    ${order.deliveryMethod === "delivery" && order.address1 ? `
      <h3 style="margin:24px 0 8px;color:#1e293b;">Delivery address</h3>
      <div style="background:#f8fafc;padding:16px;border-radius:8px;color:#1e293b;line-height:1.6;">
        ${escape(order.name || "")}<br/>
        ${escape(order.address1)}${order.address2 ? `<br/>${escape(order.address2)}` : ""}<br/>
        ${escape(order.city || "")} ${escape(order.postal || "")}<br/>
        ${escape(order.country || "")}
      </div>
    ` : ""}
  `;
  return shell(brand, "Order confirmed", `Thank you for shopping with ${brand.name}`, body);
}

export function renderOrderAdminEmail(order: OrderPayload, brandIn?: Partial<Brand>): string {
  const brand = withDefaults(brandIn);
  const body = `
    <div style="background:#fff7ed;padding:16px;border-radius:8px;margin:0 0 16px;border-left:4px solid #ea580c;">
      <h4 style="margin:0 0 4px;color:#ea580c;">⚡ New order${order.number ? ` #${escape(order.number)}` : ""}</h4>
      <p style="margin:0;color:#ea580c;font-size:14px;">${escape(order.method || "unknown")} &middot; ${escape(order.deliveryMethod || "—")} &middot; ${escape(money(order.total, order.currency))}</p>
    </div>
    <div style="background:#f8fafc;padding:16px;border-radius:8px;margin-bottom:16px;">
      <table style="width:100%;border-collapse:collapse;">
        ${row("Customer", order.name)}
        ${row("Email", order.email)}
        ${row("Phone", order.phone)}
        ${row("City", order.city)}
        ${row("Method", order.method)}
        ${row("Delivery", order.deliveryMethod)}
      </table>
    </div>
    <h3 style="margin:0 0 8px;color:#1e293b;">Items</h3>
    <div style="background:#f8fafc;padding:16px;border-radius:8px;">${itemsTable(order.items, order.currency)}</div>
  `;
  return shell(brand, "🛒 New order", `Order received for ${brand.name}`, body);
}

// ─── Booking ─────────────────────────────────────────────────────────────

export interface BookingPayload {
  reference?: string;
  serviceName?: string;
  startsAt?: string | Date;
  durationMinutes?: number;
  name?: string;
  email?: string;
  phone?: string;
  notes?: string;
}

function fmtDate(value: string | Date | undefined): string {
  if (!value) return "—";
  const d = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleString("en-US", { dateStyle: "full", timeStyle: "short" });
}

export function renderBookingCustomerEmail(booking: BookingPayload, brandIn?: Partial<Brand>): string {
  const brand = withDefaults(brandIn);
  const body = `
    <div style="background:#f0fdf4;padding:16px;border-radius:8px;margin:0 0 16px;border-left:4px solid #059669;">
      <h4 style="margin:0 0 8px;color:#059669;">✓ Booking ${booking.reference ? `#${escape(booking.reference)} ` : ""}received</h4>
      <p style="margin:0;color:#059669;font-size:14px;">We'll confirm your appointment shortly.</p>
    </div>
    <div style="background:#f8fafc;padding:16px;border-radius:8px;">
      <table style="width:100%;border-collapse:collapse;">
        ${row("Service", booking.serviceName)}
        ${row("When", fmtDate(booking.startsAt))}
        ${booking.durationMinutes ? row("Duration", `${booking.durationMinutes} min`) : ""}
        ${row("Name", booking.name)}
        ${row("Email", booking.email)}
        ${row("Phone", booking.phone)}
      </table>
      ${booking.notes ? `<div style="margin-top:16px;padding-top:16px;border-top:1px solid #e2e8f0;">
        <p style="margin:0 0 8px;color:#64748b;font-size:14px;">Your notes:</p>
        <p style="margin:0;color:#1e293b;line-height:1.6;white-space:pre-wrap;">${escape(booking.notes)}</p>
      </div>` : ""}
    </div>
  `;
  return shell(brand, "Booking received", `Thanks for booking with ${brand.name}`, body);
}

export function renderBookingAdminEmail(booking: BookingPayload, brandIn?: Partial<Brand>): string {
  const brand = withDefaults(brandIn);
  const body = `
    <div style="background:#fff7ed;padding:16px;border-radius:8px;margin:0 0 16px;border-left:4px solid #ea580c;">
      <h4 style="margin:0 0 4px;color:#ea580c;">⚡ New booking${booking.reference ? ` #${escape(booking.reference)}` : ""}</h4>
      <p style="margin:0;color:#ea580c;font-size:14px;">${escape(booking.serviceName || "Service")} &middot; ${escape(fmtDate(booking.startsAt))}</p>
    </div>
    <div style="background:#f8fafc;padding:16px;border-radius:8px;">
      <table style="width:100%;border-collapse:collapse;">
        ${row("Service", booking.serviceName)}
        ${row("When", fmtDate(booking.startsAt))}
        ${booking.durationMinutes ? row("Duration", `${booking.durationMinutes} min`) : ""}
        ${row("Customer", booking.name)}
        ${row("Email", booking.email)}
        ${row("Phone", booking.phone)}
      </table>
      ${booking.notes ? `<div style="margin-top:16px;padding-top:16px;border-top:1px solid #e2e8f0;">
        <p style="margin:0 0 8px;color:#64748b;font-size:14px;">Customer notes:</p>
        <p style="margin:0;color:#1e293b;line-height:1.6;white-space:pre-wrap;">${escape(booking.notes)}</p>
      </div>` : ""}
    </div>
  `;
  return shell(brand, "📅 New booking", `For ${brand.name}`, body);
}

